glsl3.frag:
precision highp float;
#if USE_ALPHA_TEST
layout(std140) uniform ALPHA_TEST_DATA {
  float alphaThreshold;
};
#endif
layout(std140) uniform Custom {
  vec4 sliceParams;
  vec4 edgeParams;
  vec4 cornerParams;
  vec4 edgeColor;
};
layout(std140) uniform PixelSize {
  vec2 spritePixelSize;
};
#if USE_TEXTURE
uniform sampler2D cc_spriteTexture;
#endif
vec4 CCSampleWithAlphaSeparated(sampler2D tex, vec2 uv) {
#if CC_USE_EMBEDDED_ALPHA
  return vec4(texture(tex, uv).rgb, texture(tex, uv + vec2(0.0, 0.5)).r);
#else
  return texture(tex, uv);
#endif
}
#if USE_ALPHA_TEST
#endif
void ALPHA_TEST (in vec4 color) {
  #if USE_ALPHA_TEST
    if (color.a < alphaThreshold) discard;
  #endif
}
void ALPHA_TEST (in float alpha) {
  #if USE_ALPHA_TEST
    if (alpha < alphaThreshold) discard;
  #endif
}
in vec4 color;
#if USE_TEXTURE
  in vec2 uv0;
#endif
float linear(float x0, float x1, float y0, float y1, float inputX) {
  return (y1 - y0) * (inputX - x0) / (x1 - x0) + y0;
}
float pixelToUV(float pixel, float totalPixels) {
  return pixel / totalPixels;
}
vec4 frag() {
  vec4 o = vec4(1, 1, 1, 1);
  #if USE_TEXTURE
    float pixelOffset = 1.0;
    float uvOffsetX = pixelOffset / spritePixelSize.x;
    float uvOffsetY = pixelOffset / spritePixelSize.y;
    float xCount = sliceParams.x;
    float yCount = sliceParams.y;
    float xStep = 1.0 / xCount;
    float yStep = 1.0 / yCount;
    float xCur = sliceParams.z;
    float yCur = sliceParams.w;
    float x = linear(0.0, 1.0, xCur * xStep, (xCur + 1.0) * xStep, uv0.x);
    float y = linear(0.0, 1.0, yCur * yStep, (yCur + 1.0) * yStep, uv0.y);
    vec2 sliced_uv = vec2(x, y);
    o *= CCSampleWithAlphaSeparated(cc_spriteTexture, sliced_uv);
    float edgeRightUV = pixelToUV(edgeParams.x, spritePixelSize.x);
    float edgeLeftUV = pixelToUV(edgeParams.y, spritePixelSize.x);
    float edgeBottomUV = pixelToUV(edgeParams.z, spritePixelSize.y);
    float edgeTopUV = pixelToUV(edgeParams.w, spritePixelSize.y);
    float cornerRightUV = pixelToUV(cornerParams.x, spritePixelSize.x);
    float cornerLeftUV = pixelToUV(cornerParams.y, spritePixelSize.x);
    float cornerBottomUV = pixelToUV(cornerParams.z, spritePixelSize.y);
    float cornerTopUV = pixelToUV(cornerParams.w, spritePixelSize.y);
    float s0 = 1.0 - smoothstep(1.0 - edgeRightUV, 1.0, uv0.x - uvOffsetX);
    float s2 = smoothstep(0.0, edgeLeftUV, uv0.x + uvOffsetX);
    float s1 = 1.0 - smoothstep(1.0 - edgeBottomUV, 1.0, uv0.y - uvOffsetY);
    float s3 = smoothstep(0.0, edgeTopUV, uv0.y + uvOffsetY);
    float _alpha = s0 * s1 * s2 * s3 * 1.0;
    float alpha = smoothstep(0.2, 0.2 + 0.2, _alpha);
    float black = smoothstep(0.05, 0.09, _alpha);
    float c0 = smoothstep(1.0 - cornerRightUV, 1.0, uv0.x - 0.01);
    float c2 = 1.0 - smoothstep(0.0, cornerLeftUV, uv0.x + 0.01);
    float c1 = smoothstep(1.0 - cornerTopUV, 1.0, uv0.y - 0.01);
    float c3 = 1.0 - smoothstep(0.0, cornerBottomUV, uv0.y + 0.01);
    float _alpha2 = c0 * c1 + c1 * c2 + c2 * c3 + c3 * c0;
    float alpha2 = 1.0 - smoothstep(0.95, 0.95 + 0.02, _alpha2);
    float black2 = 1.0 - smoothstep(0.90, 0.90 + 0.02, _alpha2);
    float alpha_factor = min(alpha, alpha2);
    float black_factor = min(black, black2);
    o.a = black_factor;
    o.rgb = mix(edgeColor.rgb, o.rgb, alpha_factor);
    #if IS_GRAY
      float gray = 0.2126 * o.r + 0.7152 * o.g + 0.0722 * o.b;
      o.r = o.g = o.b = gray;
    #endif
  #endif
  o *= color;
  ALPHA_TEST(o);
  return o;
}
layout(location = 0) out vec4 cc_FragColor;
void main() { cc_FragColor = frag(); }

